import { MinusCircleOutlined, PlusCircleFilled } from '@ant-design/icons';
import React, { useState } from 'react';
import {  Card, Skeleton, Switch } from 'antd';
import { Button } from 'antd';


const CardItem: React.FC = () => {
  const [loading, setLoading] = useState<boolean>(false);
  const [Counter, setCounter] = useState<number>(1);
  const [Price, setPrice] = useState<number>(210);


  const onChange = (checked: boolean) => {
    setLoading(!checked);
  };

  return (
    <>
      <Switch checked={!loading} onChange={onChange} />
      <Skeleton loading={loading} active avatar  style={{ width: 340, marginTop: 22 }}>
      <Card className='CardItem'  style={{ width: 340, marginTop: 16 }} loading={loading}>
      <span className='Card_Counter'>
        <Button  shape="circle" icon={<PlusCircleFilled />} onClick={()=>setCounter(v => ++v)} />
        <div className='Counter'>
          {Counter}
        </div>
        <Button  shape="circle" icon={<MinusCircleOutlined />} onClick={()=>setCounter(v => v > 0 ? --v : v)} />
      </span>
      <span className='Card_Img'>
      <img alt=''  src='../Product/Product.png'   />
      </span>
      <span className='Card_Info'>
        <h5> Silver High Neck Sweater </h5>
        <h6>  Neck Sweater </h6>
        <strong> ${210.00} </strong>
      </span>
      </Card>
      </Skeleton>

    </>
  );
};

export default CardItem;
